input.content:
[
  {
    "order": 1,
    "title": "项目概览",
    "description": "了解 OpenCoreSDK 的定位：Android coredump 捕获与解析库。核心能力包括 ELF Core Dump 生成、Stop-the-World 线程暂停、ptrace 内存读取、PAC/TLS/MTE 架构特性支持。支持 7 种 CPU 架构 (arm64, arm, x86, x86_64, riscv64, lp32, lp64)。",
    "nodeIds": ["document:README.md"]
  },
  {
    "order": 2,
    "title": "Java SDK API 入口",
    "description": "Coredump.java 是 SDK 的主入口，采用单例模式设计。它管理 Java 和 Native 两种 crash 的捕获，通过 Handler 实现异步事件处理。关键方法：init() 初始化 native 引擎，enable() 注册异常处理器，doCoredump() 触发 core dump，setListener() 设置完成回调。",
    "nodeIds": ["file:opencore/src/main/java/penguin/opencore/sdk/Coredump.java"],
    "languageLesson": "Java Handler 机制：Handler 用于线程间通信，coredump Handler 线程专门处理 core 生成事件，post-work Handler 处理后续清理工作。"
  },
  {
    "order": 3,
    "title": "JNI 桥接层",
    "description": "opencore_jni.cpp 实现了 Java Native Interface 桥接层。它负责：注册 native 方法到 JavaVM、建立 Java 线程与 native 线程的回调机制、处理 JNI 环境的 attach/detach。关键函数：Java_penguin_opencore_sdk_Coredump_nativeInit 完成 JNI_OnLoad 初始化。",
    "nodeIds": ["file:opencore/src/main/cpp/opencore_jni.cpp"],
    "languageLesson": "JNI 回调模式：pthread_join 等待 native 完成，callback 异步通知 Java 层。使用 GlobalRef 保持对 Java 对象的引用。"
  },
  {
    "order": 4,
    "title": "Android 线程管理",
    "description": "eajni/AndroidJNI.cpp 和 Thread.cpp 提供了 Android 环境下的线程管理能力。包括 JNI 环境的线程附加、JavaVM 获取、以及在 native 线程中创建 Java 线程执行回调的机制。",
    "nodeIds": ["file:opencore/src/main/cpp/eajni/AndroidJNI.cpp", "file:opencore/src/main/cpp/eajni/Thread.cpp", "file:opencore/src/main/cpp/eajni/include/eajnis/Thread.h"],
    "languageLesson": "Android JNI 线程模型：native 线程需要通过 AttachCurrentThread 附加到 JVM 才能访问 JNIEnv，执行完成后通过 DetachCurrentThread 分离。"
  },
  {
    "order": 5,
    "title": "核心引擎架构",
    "description": "opencore/opencore.h/cpp 是核心引擎，实现了信号捕获、core dump 生成、ptrace 线程控制等核心功能。核心流程：HandleSignal 捕获 crash 信号 → Enable 安装信号处理器 → Dump 生成 ELF core → StopTheWorld 暂停所有线程 → ParseMaps 解析内存映射。",
    "nodeIds": ["file:opencore/src/main/cpp/opencore/opencore.h", "file:opencore/src/main/cpp/opencore/opencore.cpp"],
    "languageLesson": "模板特化模式：OpencoreImpl 通过模板参数区分不同架构（lp64::OpencoreImpl），实现统一的接口和架构特定的实现。"
  },
  {
    "order": 6,
    "title": "ELF Core Dump 生成",
    "description": "Dump() 函数是 core dump 的核心生产者。它写入 ELF 格式的核心文件，包含 NT_PRSTATUS（进程状态）、NT_PRPSINFO（进程信息）、NT_AUXV（辅助向量）等 note sections，以及内存映射段。使用 fork 创建子进程执行 dump，避免阻塞主线程。",
    "nodeIds": ["function:opencore/src/main/cpp/opencore/opencore.cpp:Dump", "function:opencore/src/main/cpp/opencore/opencore.cpp:IsFilterSegment", "function:opencore/src/main/cpp/opencore/opencore.cpp:ParseMaps"],
    "languageLesson": "ELF Core Dump 结构：ehdr (ELF header) + phdr (program headers) + notes (NT_PRSTATUS等) + memory segments。prstatus 包含寄存器上下文。"
  },
  {
    "order": 7,
    "title": "ptrace 线程同步",
    "description": "StopTheWorld/StopTheThread/Continue 实现了完整的线程同步机制。通过读取 /proc/self/task 枚举所有线程，使用 PTRACE_ATTACH 停止每个线程，dump 完成后用 PTRACE_DETACH 恢复。",
    "nodeIds": ["function:opencore/src/main/cpp/opencore/opencore.cpp:StopTheWorld", "function:opencore/src/main/cpp/opencore/opencore.cpp:StopTheThread", "function:opencore/src/main/cpp/opencore/opencore.cpp:Continue"],
    "languageLesson": "ptrace Stop-the-World：PTRACE_SEIZE 附加线程（不阻塞），PTRACE_CONT 恢复线程。通过 /proc/self/task 枚举线程 ID。"
  },
  {
    "order": 8,
    "title": "ARM64 架构实现",
    "description": "arm64/opencore.h/cpp 实现了 ARM64 特定的 coredump 功能。包括：通用寄存器读取 (CreateCorePrStatus)、浮点/SIMD 寄存器 (WriteCoreFpRegs)、TLS 读取 (WriteCoreTLS)、PAC 指针认证码 (WriteCorePAC)、MTE 内存标签 (WriteCoreMTE)。",
    "nodeIds": ["file:opencore/src/main/cpp/opencore/arm64/opencore.h", "file:opencore/src/main/cpp/opencore/arm64/opencore.cpp"],
    "languageLesson": "ARM64 特殊寄存器：PAC (Pointer Authentication Code) 用于指令签名验证，MTE (Memory Tagging Extension) 用于内存安全标记，TLS (Thread Local Storage) 保存线程本地数据。"
  },
  {
    "order": 9,
    "title": "其他架构实现",
    "description": "项目支持 6 种架构：arm (32位)、x86、x86_64、riscv64、lp32 (32位长指针模式)、lp64 (64位长指针模式)。各架构在对应目录下实现 OpencoreImpl 特化版本，处理特定寄存器和 ABI 差异。",
    "nodeIds": ["file:opencore/src/main/cpp/opencore/arm/opencore.cpp", "file:opencore/src/main/cpp/opencore/x86/opencore.cpp", "file:opencore/src/main/cpp/opencore/x86_64/opencore.cpp", "file:opencore/src/main/cpp/opencore/riscv64/opencore.cpp", "file:opencore/src/main/cpp/opencore/lp32/opencore.cpp", "file:opencore/src/main/cpp/opencore/lp64/opencore.cpp"]
  },
  {
    "order": 10,
    "title": "测试应用与构建",
    "description": "app/ 目录包含测试应用 MainActivity，展示 SDK 的使用方法。native-lib.cpp 演示如何触发 native crash。构建脚本 build_opencore.sh 支持通过环境变量指定 BUILD_ANDROID_ABIS 等参数进行定制化编译。",
    "nodeIds": ["file:app/src/main/java/penguin/opencore/tester/MainActivity.java", "file:app/src/main/cpp/native-lib.cpp", "file:script/build_opencore.sh", "file:opencore/build.gradle"]
  },
  {
    "order": 11,
    "title": "调试与验证方法",
    "description": "core-parser 工具可解析生成的 ELF core 文件，提取线程堆栈 (bt)、寄存器状态、内存映射等信息。gdb 可用于更深入的单步调试。logcat 中 Opencore 标签可跟踪运行时状态。",
    "nodeIds": ["document:README.md"],
    "languageLesson": "core-parser 使用：set sysroot symbols/ 设置符号目录，bt 命令查看线程堆栈，info registers 查看寄存器。readelf -n core.file 查看 ELF notes。"
  }
]
